1	const PROCESSING_FEE = 5;
2	const BASE_PREMIUM: Record<string, number> = {
3	  sword: 100,
4	  amulet: 60,
5	  staff: 80,
6	  potion: 40,
7	  rune: 25,
8	  moonstone: 25,
9	};
10	
11	type Item = {
12	  type: string;
13	  material?: string;
14	  enchantment?: number;
15	  cursed?: boolean;
16	};
17	type QuoteStep = { op: "quote"; items: Item[] };
18	type Damage = { itemType: string; amount: number };
19	type ClaimStep = {
20	  op: "claim";
21	  policy: number;
22	  incident: { cause: string; damages: Damage[] };
23	};
24	type Step = QuoteStep | ClaimStep;
25	type Customer = { yearsWithMHPCO: number };
26	type Scenario = { customer: Customer; steps: Step[] };
27	
28	const basePremiumFor = (type: string): number => BASE_PREMIUM[type] ?? 0;
29	
30	const INSURANCE_VALUE: Record<string, number> = {
31	  sword: 1000,
32	  amulet: 600,
33	  staff: 800,
34	  potion: 400,
35	  rune: 250,
36	  moonstone: 250,
37	};
38	
39	const insuranceValueFor = (type: string): number => INSURANCE_VALUE[type] ?? 0;
40	
41	const DEDUCTIBLE = 100;
42	const CAP_MULTIPLIER = 2;
43	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
44	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
45	
46	const FIRST_INSURANCE_RATE = 0.1;
47	
48	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
49	const BLOCK_SIZE = 3;
50	const BLOCK_BASE_PREMIUM = 60;
51	
52	const countByType = (items: Item[]): Map<string, number> => {
53	  const counts = new Map<string, number>();
54	  for (const item of items) {
55	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
56	  }
57	  return counts;
58	};
59	
60	const groupBase = (type: string, count: number): number =>
61	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE
62	    ? BLOCK_BASE_PREMIUM
63	    : count * basePremiumFor(type);
64	
65	const policyBase = (items: Item[]): number =>
66	  Array.from(countByType(items)).reduce(
67	    (total, [type, count]) => total + groupBase(type, count),
68	    0,
69	  );
70	
71	const LOYALTY_RATE = 0.2;
72	const LOYALTY_THRESHOLD_YEARS = 2;
73	const FOLLOW_UP_RATE = 0.15;
74	
75	type PolicyContext = { customer: Customer; isFollowUp: boolean };
76	
77	type PolicyModifier = {
78	  applies: (ctx: PolicyContext) => boolean;
79	  rate: number;
80	  sign: 1 | -1;
81	};
82	
83	const POLICY_MODIFIERS: PolicyModifier[] = [
84	  { applies: () => true, rate: FIRST_INSURANCE_RATE, sign: +1 },
85	  {
86	    applies: (ctx) => ctx.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS,
87	    rate: LOYALTY_RATE,
88	    sign: -1,
89	  },
90	  { applies: (ctx) => ctx.isFollowUp, rate: FOLLOW_UP_RATE, sign: -1 },
91	];
92	
93	const policyAdjustments = (base: number, ctx: PolicyContext): number =>
94	  POLICY_MODIFIERS.reduce(
95	    (total, mod) => total + (mod.applies(ctx) ? mod.sign * base * mod.rate : 0),
96	    0,
97	  );
98	
99	const CURSE_RATE = 0.5;
100	const HIGH_ENCHANTMENT_RATE = 0.3;
101	const HIGH_ENCHANTMENT_THRESHOLD = 5;
102	
103	const surchargeWhen = (item: Item, applies: boolean, rate: number): number =>
104	  applies ? basePremiumFor(item.type) * rate : 0;
105	
106	const curseSurcharge = (item: Item): number =>
107	  surchargeWhen(item, item.cursed === true, CURSE_RATE);
108	
109	const highEnchantmentSurcharge = (item: Item): number =>
110	  surchargeWhen(
111	    item,
112	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
113	    HIGH_ENCHANTMENT_RATE,
114	  );
115	
116	const itemSurcharges = (items: Item[]): number =>
117	  items.reduce(
118	    (sum, item) => sum + curseSurcharge(item) + highEnchantmentSurcharge(item),
119	    0,
120	  );
121	
122	const quotePremium = (items: Item[], ctx: PolicyContext): number => {
123	  const base = policyBase(items);
124	  return Math.ceil(
125	    base + itemSurcharges(items) + policyAdjustments(base, ctx) + PROCESSING_FEE,
126	  );
127	};
128	
129	const insuranceSum = (items: Item[]): number =>
130	  items.reduce((sum, item) => sum + insuranceValueFor(item.type), 0);
131	
132	const reimbursable = (amount: number, item: Item | undefined): number =>
133	  item !== undefined &&
134	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
135	    ? amount * HIGH_ENCHANTMENT_PAYOUT_RATE
136	    : amount;
137	
138	const damagePayout = (damage: Damage, item: Item | undefined): number =>
139	  reimbursable(damage.amount, item) - DEDUCTIBLE;
140	
141	const claimPayout = (claim: ClaimStep, items: Item[]): number =>
142	  claim.incident.damages.reduce(
143	    (sum, d) => sum + damagePayout(d, items.find((i) => i.type === d.itemType)),
144	    0,
145	  );
146	
147	type QuoteResult = { premium: number };
148	type ClaimResult = { payout: number; remainingCap: number };
149	type StepResult = QuoteResult | ClaimResult;
150	type ScenarioResult = { results: StepResult[] };
151	
152	type PolicyLedger = {
153	  registerQuote: (index: number, items: Item[]) => void;
154	  isFollowUp: () => boolean;
155	  itemsFor: (policy: number) => Item[];
156	  recordClaim: (policy: number, payout: number) => number;
157	};
158	
159	const createPolicyLedger = (): PolicyLedger => {
160	  const remainingCaps = new Map<number, number>();
161	  const policyItems = new Map<number, Item[]>();
162	  return {
163	    registerQuote: (index, items) => {
164	      remainingCaps.set(index, CAP_MULTIPLIER * insuranceSum(items));
165	      policyItems.set(index, items);
166	    },
167	    isFollowUp: () => remainingCaps.size > 0,
168	    itemsFor: (policy) => policyItems.get(policy) ?? [],
169	    recordClaim: (policy, payout) => {
170	      const remaining = (remainingCaps.get(policy) ?? 0) - payout;
171	      remainingCaps.set(policy, remaining);
172	      return remaining;
173	    },
174	  };
175	};
176	
177	const handleQuote = (
178	  step: QuoteStep,
179	  index: number,
180	  customer: Customer,
181	  ledger: PolicyLedger,
182	): QuoteResult => {
183	  const ctx: PolicyContext = { customer, isFollowUp: ledger.isFollowUp() };
184	  ledger.registerQuote(index, step.items);
185	  return { premium: quotePremium(step.items, ctx) };
186	};
187	
188	const handleClaim = (step: ClaimStep, ledger: PolicyLedger): ClaimResult => {
189	  const payout = claimPayout(step, ledger.itemsFor(step.policy));
190	  const remainingCap = ledger.recordClaim(step.policy, payout);
191	  return { payout, remainingCap };
192	};
193	
194	export const processScenario = (scenario: Scenario): ScenarioResult => {
195	  const ledger = createPolicyLedger();
196	  const results = scenario.steps.map((step, index) =>
197	    step.op === "quote"
198	      ? handleQuote(step, index, scenario.customer, ledger)
199	      : handleClaim(step, ledger),
200	  );
201	  return { results };
202	};
